_EVAL_GLOBALS: dict[str, Any] = {
    "__builtins__": {
        "bool": bool,
        "dict": dict,
        "len": len,
        "sum": sum,
        "tuple": tuple,
    },
    "event_alpha_artifacts": event_alpha_artifacts,
    "event_alpha_namespace_status": event_alpha_namespace_status,
}


def build_legacy_doctor_result(ctx: SimpleNamespace) -> EventAlphaArtifactDoctorResult:
    values = vars(ctx).copy()
    kwargs = {
        field: eval(expression, _EVAL_GLOBALS, values)
        for field, expression in RESULT_FIELD_EXPRESSIONS
    }
    return EventAlphaArtifactDoctorResult(**kwargs)


__all__ = ('RESULT_FIELD_EXPRESSIONS', 'build_legacy_doctor_result')
